/** Scroll-reveal: fades/slides content in once it enters the viewport. */
function useReveal(threshold = 0.15) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(prefersReducedMotion);
  useEffect(() => {
    if (prefersReducedMotion) return undefined;
    const el = ref.current;
    if (!el) return undefined;
    const obs = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          obs.disconnect();
        }
      },
      { threshold }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, [threshold]);
  return [ref, visible];
}

function Reveal({ children, delay = 0 }) {
  const [ref, visible] = useReveal();
  return (
    <div
      ref={ref}
      style={{
        opacity: visible ? 1 : 0,
        transform: visible ? 'translateY(0) scale(1)' : 'translateY(26px) scale(0.985)',
        transition: `opacity 0.8s cubic-bezier(0.16,1,0.3,1) ${delay}s, transform 0.8s cubic-bezier(0.16,1,0.3,1) ${delay}s`,
      }}
    >
      {children}
    </div>
  );
}

/** Parallax: shifts an element at a fraction of scroll speed. Skipped on touch
 *  devices and reduced-motion, and rAF-throttled so it never runs more than
 *  once per frame — a mobile-performance guard, not just a desktop nicety. */
function useParallax(speed = 0.15) {
  const ref = useRef(null);
  useEffect(() => {
    if (prefersReducedMotion || isCoarsePointer) return undefined;
    let ticking = false;
    const handler = () => {
      if (ticking) return;
      ticking = true;
      requestAnimationFrame(() => {
        ticking = false;
        if (ref.current) ref.current.style.transform = `translateY(${window.scrollY * speed}px)`;
      });
    };
    window.addEventListener('scroll', handler, { passive: true });
    return () => window.removeEventListener('scroll', handler);
  }, [speed]);
  return ref;
}

/**
 * RepelText — the Pretext-inspired centerpiece. Splits copy into words or
 * characters and pushes each one away from the cursor within a radius.
 * Positions are measured once (and on resize) — never re-measured on
 * mousemove — so there is zero layout reflow in the hot path, only
 * transform updates inside requestAnimationFrame. Disabled entirely on
 * touch devices, where hover doesn't exist and it would only cost battery.
 */
function RepelText({ text, mode = 'word', className, style, radius = 100, strength = 30 }) {
  const containerRef = useRef(null);
  const itemRefs = useRef([]);
  const positions = useRef([]);
  const raf = useRef(false);
  const items = mode === 'char' ? text.split('') : text.split(' ');
  itemRefs.current = [];

  useEffect(() => {
    if (isCoarsePointer) return undefined;
    const measure = () => {
      if (!containerRef.current) return;
      const box = containerRef.current.getBoundingClientRect();
      positions.current = itemRefs.current.map((el) => {
        if (!el) return { cx: 0, cy: 0 };
        const r = el.getBoundingClientRect();
        return { cx: r.left + r.width / 2 - box.left, cy: r.top + r.height / 2 - box.top };
      });
    };
    measure();
    window.addEventListener('resize', measure);
    return () => window.removeEventListener('resize', measure);
  }, [text, mode]);

  const handleMove = (e) => {
    if (prefersReducedMotion || isCoarsePointer || raf.current) return;
    raf.current = true;
    const box = containerRef.current.getBoundingClientRect();
    const mx = e.clientX - box.left;
    const my = e.clientY - box.top;
    requestAnimationFrame(() => {
      raf.current = false;
      positions.current.forEach((pos, i) => {
        const el = itemRefs.current[i];
        if (!el) return;
        const dx = pos.cx - mx;
        const dy = pos.cy - my;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < radius) {
          const force = (1 - dist / radius) * strength;
          const ang = Math.atan2(dy, dx);
          el.style.transform = `translate(${(Math.cos(ang) * force).toFixed(1)}px, ${(Math.sin(ang) * force).toFixed(1)}px)`;
        } else {
          el.style.transform = 'translate(0px, 0px)';
        }
      });
    });
  };

  const handleLeave = () => {
    itemRefs.current.forEach((el) => { if (el) el.style.transform = 'translate(0px, 0px)'; });
  };

  return (
    <p
      ref={containerRef}
      onMouseMove={handleMove}
      onMouseLeave={handleLeave}
      className={className}
      style={{ ...style, cursor: prefersReducedMotion || isCoarsePointer ? 'auto' : 'crosshair' }}
    >
      {items.map((it, i) => (
        <span
          key={i}
          ref={(el) => (itemRefs.current[i] = el)}
          className="inline-block transition-transform duration-150 ease-out"
          style={mode === 'word' ? { marginRight: '0.28em' } : undefined}
        >
          {mode === 'char' && it === ' ' ? '\u00A0' : it}
        </span>
      ))}
    </p>
  );
}

