function VoiceNote({ t }) {
  const audioRef = useRef(null);
  const [playing, setPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [tier, setTier] = useState('custom'); // 'custom' -> 'native' -> 'unavailable'
  const bars = [6, 12, 18, 10, 22, 14, 8, 20, 12, 16, 9, 24, 13, 7, 18, 11, 15, 8, 20, 10];

  const toggle = () => {
    if (!audioRef.current) return;
    if (playing) {
      audioRef.current.pause();
    } else {
      const p = audioRef.current.play();
      if (p && typeof p.catch === 'function') {
        p.catch(() => setTier('native'));
      }
    }
  };

  const handleTimeUpdate = () => {
    const a = audioRef.current;
    if (a && a.duration) setProgress(a.currentTime / a.duration);
  };

  if (tier === 'unavailable') {
    return (
      <div
        className="inline-flex items-center gap-2 px-4 py-2.5 rounded-full border text-sm"
        style={{ borderColor: t.border, backgroundColor: t.surface, color: t.muted }}
      >
        🎙️ Voice intro — plays on the live site
      </div>
    );
  }

  if (tier === 'native') {
    return (
      <div
        className="inline-flex items-center gap-3 px-4 py-2 rounded-full border max-w-xs"
        style={{ borderColor: t.border, backgroundColor: t.surface }}
      >
        <audio
          controls
          preload="auto"
          src={VOICE_NOTE}
          onError={() => setTier('unavailable')}
          style={{ height: 32, maxWidth: 220 }}
        />
      </div>
    );
  }

  return (
    <div
      className="inline-flex items-center gap-3 px-4 py-3 rounded-full border max-w-xs"
      style={{ borderColor: t.border, backgroundColor: t.surface }}
    >
      <audio
        ref={audioRef}
        src={VOICE_NOTE}
        preload="auto"
        onPlay={() => setPlaying(true)}
        onPause={() => setPlaying(false)}
        onEnded={() => { setPlaying(false); setProgress(0); }}
        onTimeUpdate={handleTimeUpdate}
        onError={() => setTier('native')}
      />
      <button
        onClick={toggle}
        aria-label={playing ? 'Pause voice note' : 'Play voice note'}
        className="w-9 h-9 rounded-full flex items-center justify-center text-white shrink-0"
        style={{ backgroundColor: RUST }}
      >
        {playing ? <Pause size={15} /> : <Play size={15} style={{ marginLeft: 2 }} />}
      </button>
      <div className="flex items-center gap-[2px] h-6">
        {bars.map((h, i) => {
          const active = i / bars.length < progress;
          return (
            <span
              key={i}
              className="w-[3px] rounded-full transition-colors duration-150"
              style={{ height: `${h}px`, backgroundColor: active ? RUST : t.border }}
            />
          );
        })}
      </div>
      <span className="text-xs shrink-0" style={{ color: t.faint }}>0:06</span>
    </div>
  );
}

